#include <iostream>
#include <algorithm>
using namespace std;
struct person
{
    string num;
    int order,chang;
};
person a[25];
bool func(person x,person y)
{
    if(x.chang!=y.chang)
    {
        return x.chang>y.chang;
    }
    else
    {
        return x.num>y.num;
    }
}
int main() 
{
    int n;
    cin>>n;
    for(int i=0;i<=n-1;i++)
    {
        cin>>a[i].num;
        a[i].order=i+1;
        a[i].chang=a[i].num.size();
    }
    sort(a,a+n,func);
    cout<<a[0].order<<endl<<a[0].num;
    return 0;
}
